#include "test_framework.hpp"
#include "mst/mst.hpp"
#include <initializer_list>

using namespace cryo;
using namespace cryo_test;

namespace {

void add_nodes(Graph& g, std::initializer_list<NodeId> ids) {
    for (NodeId id : ids) {
        g.add_node_with_id(id);
    }
}

void assert_connected_mst_parity(const Graph& g, NodeId start = 0) {
    auto km = kruskal(g);
    auto pm = prim(g, start);
    auto bm = boruvka(g);

    assert_near(bm.total_weight, km.total_weight, 1e-9, "boruvka vs kruskal");
    assert_near(bm.total_weight, pm.total_weight, 1e-9, "boruvka vs prim");
    assert_true(is_spanning_tree(g, bm), "boruvka result should span connected graph");
    assert_eq(bm.edges.size(), g.node_count() - 1, "connected MST edge count");
    assert_false(bm.is_forest, "connected graph should not produce forest flag");
}

} // namespace

CRYO_TEST(MST, BoruvkaUsesBothEndpointComponentsForCheapestEdge) {
    Graph g(GraphType::Undirected);
    add_nodes(g, {0, 1, 2});
    g.add_edge(0, 1, 1.0);
    g.add_edge(0, 2, 1.0);
    g.add_edge(1, 2, 100.0);

    auto bm = boruvka(g);

    assert_near(bm.total_weight, 2.0);
    assert_connected_mst_parity(g);
}

CRYO_TEST(MST, BoruvkaMatchesParityWithEqualWeightEdges) {
    Graph g(GraphType::Undirected);
    add_nodes(g, {0, 1, 2, 3});
    g.add_edge(0, 1, 1.0);
    g.add_edge(0, 2, 1.0);
    g.add_edge(0, 3, 1.0);
    g.add_edge(1, 2, 1.0);
    g.add_edge(1, 3, 1.0);
    g.add_edge(2, 3, 1.0);

    auto bm = boruvka(g);

    assert_near(bm.total_weight, 3.0);
    assert_connected_mst_parity(g);
}

CRYO_TEST(MST, BoruvkaHandlesMultipleComponentMergesInOnePhase) {
    Graph g(GraphType::Undirected);
    add_nodes(g, {0, 1, 2, 3, 4, 5});
    g.add_edge(0, 1, 1.0);
    g.add_edge(2, 3, 1.0);
    g.add_edge(4, 5, 1.0);
    g.add_edge(1, 2, 2.0);
    g.add_edge(3, 4, 2.0);
    g.add_edge(0, 2, 4.0);
    g.add_edge(1, 4, 5.0);
    g.add_edge(0, 5, 9.0);

    auto bm = boruvka(g);

    assert_near(bm.total_weight, 7.0);
    assert_connected_mst_parity(g);
}

CRYO_TEST(MST, BoruvkaHandlesSingleNodeGraph) {
    Graph g(GraphType::Undirected);
    g.add_node_with_id(42);

    auto km = kruskal(g);
    auto pm = prim(g, 42);
    auto bm = boruvka(g);

    assert_near(bm.total_weight, 0.0);
    assert_near(bm.total_weight, km.total_weight);
    assert_near(bm.total_weight, pm.total_weight);
    assert_true(bm.edges.empty());
    assert_true(is_spanning_tree(g, bm));
    assert_false(bm.is_forest);
}

CRYO_TEST(MST, BoruvkaMatchesKruskalForestWeightOnDisconnectedGraph) {
    Graph g(GraphType::Undirected);
    add_nodes(g, {0, 1, 2, 3, 4, 5, 6});
    g.add_edge(0, 1, 1.0);
    g.add_edge(1, 2, 2.0);
    g.add_edge(0, 2, 10.0);
    g.add_edge(3, 4, 4.0);
    g.add_edge(4, 5, 1.0);
    g.add_edge(3, 5, 2.0);

    auto km = kruskal(g);
    auto bm = boruvka(g);

    assert_near(bm.total_weight, km.total_weight, 1e-9, "disconnected forest weight");
    assert_near(bm.total_weight, 6.0);
    assert_eq(bm.edges.size(), (size_t)4, "disconnected forest edge count");
    assert_true(bm.is_forest);
    assert_false(is_spanning_tree(g, bm));
}

